package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.BedragMetCarryOver;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.OverdrachtKey;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckBasisRszPositief;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ExtractBasisRszPositief;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.Set;

@Slf4j
@AllArgsConstructor
public class WerkbonusVerdeler {

    private static final LocalDate START_WIJZING_WERKBONUS_VERDELING = new LocalDate(2020, 4, 1);
    private static final Set<Integer> EXTRA_LOONCODES_OVERDRACHT = ImmutableSet.of(318, 328, 338);
    private static final Set<Integer> EXTRA_LOONCODES_VERDELING = ImmutableSet.of(320);

    private final BijdragePercentagesFactory bijdragePercentagesFactory;
    private final WerkbonusKomtInAanmerking komtInAanMerking;

    public void verdeel(
            Money bedragVermindering, Money overdrachtWerkbonus, RekenContext opdrachtContext, Opdracht opdracht, RekenTijd rekenTijd, WerkbonusLuik werkbonusLuik) {
        Collection<LoonElement> werkBonusElementen = bepaalWerkBonusElementen(bedragVermindering, opdrachtContext, opdracht, rekenTijd);

        Money totaalBasis = bepaalTotaalPositieveBasis(werkBonusElementen);
        Money negatieveBijdragen = bepaalNegatieveBijdragen(werkBonusElementen);

        Money totaalWerkbonus =
                verdeelWerkbonusRekeningHoudenMetNegatieveBijdragen(bedragVermindering, totaalBasis, negatieveBijdragen, werkBonusElementen, werkbonusLuik);
        verdeelOverdrachtWerkbonus(bedragVermindering, overdrachtWerkbonus, opdrachtContext, totaalBasis, totaalWerkbonus, werkBonusElementen, rekenTijd, werkbonusLuik);
        opdrachtContext.put(werkbonusLuik.getBedragKey(), totaalWerkbonus);
    }

    private Money verdeelWerkbonusRekeningHoudenMetNegatieveBijdragen(
            Money bedragVermindering, Money totaalBasis, Money negatieveBijdragen, Collection<LoonElement> werkBonusElementen, WerkbonusLuik werkbonusLuik) {
        Money carry = Money.ZERO;
        Money carryNegatief = Money.ZERO;
        Money totaalWerkbonus = Money.ZERO;
        log.debug("verdeelWerkbonus-bedragVermindering:{};totaalBasis:{}", bedragVermindering, totaalBasis);
        for (LoonElement loonElement : werkBonusElementen) {
            Money basis = loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY);
            basis = basis.add(loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_TAO_KEY));
            log.debug("basis:{};loonElement:{}", basis, loonElement);
            if (basis.signum() > 0) {
                BedragMetCarryOver begrenzing = bepaalRszBijdrageVoorBegrenzing(loonElement, basis, totaalBasis, negatieveBijdragen, carryNegatief, werkbonusLuik);
                carryNegatief = begrenzing.getCarryover();

                Money werkbonus = bedragVermindering.multiply(basis.divide(totaalBasis)).add(carry);
                werkbonus = werkbonus.min(begrenzing.getBedrag()).max(Money.ZERO);
                carry = werkbonus.subtract(werkbonus.round(2));
                werkbonus = werkbonus.round(2);

                log.debug("werkbonus:{};carry:{}", werkbonus, carry);
                totaalWerkbonus = totaalWerkbonus.add(werkbonus);

                loonElement.putProperty(werkbonusLuik.getBedragKey(), werkbonus);
            }
        }
        return totaalWerkbonus;
    }

    private BedragMetCarryOver bepaalRszBijdrageVoorBegrenzing(
            LoonElement loonElement, Money basis, Money totaalBasis, Money negatieveBijdragen, Money carryNegatief,
            WerkbonusLuik werkbonusLuik) {
        Money deelNegatief = negatieveBijdragen.multiply(basis.divide(totaalBasis)).add(carryNegatief);
        carryNegatief = deelNegatief.subtract(deelNegatief.round(2));
        deelNegatief = deelNegatief.round(2);

        Money bijdrage = loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
        bijdrage = bijdrage.add(loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY));
        bijdrage = bijdrage.add(deelNegatief);
        bijdrage = bijdrage.subtract(loonElement.getPropertyMoney(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY));
        if (werkbonusLuik == WerkbonusLuik.LUIK_B) {
            bijdrage = bijdrage.subtract(loonElement.getPropertyMoney(RekenRszKey.WERKBONUS_LAGE_LONEN_KEY));
        }
        return new BedragMetCarryOver(bijdrage, carryNegatief);
    }

    private void verdeelOverdrachtWerkbonus(
            Money bedragVermindering, Money overdrachtWerkbonus, RekenContext opdrachtContext, Money totaalBasis, Money totaalWerkbonus,
            Collection<LoonElement> werkBonusElementen,
            RekenTijd rekenTijd, WerkbonusLuik werkbonusLuik) {
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        Money overdracht = bedragVermindering.subtract(totaalWerkbonus);
        if (overdracht.signum() > 0 || overdrachtWerkbonus.signum() != 0) {
            Money gebruikteOverdracht = totaalWerkbonus.subtract(bedragVermindering.subtract(overdrachtWerkbonus));
            if (gebruikteOverdracht.signum() > 0) {
                overdracht = gebruikteOverdracht.negate();
            } else {
                overdracht = gebruikteOverdracht.negate();
                Money overblijvendeOverdracht = overdrachtWerkbonus.subtract(gebruikteOverdracht);
                Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
                Money maxOverdracht = bepaalMaxOverdrachtWerkbonus(werkBonusElementen, overblijvendeOverdracht, opper, rekenTijd, regulManager);
                overdracht = overdracht.add(overblijvendeOverdracht).min(maxOverdracht).subtract(overblijvendeOverdracht).max(Money.ZERO);
            }

            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(new OverdrachtKey(werkbonusLuik.getBedragKey()), overdracht, ExtractBasisRszPositief.DEFAULT,
                    totaalBasis,
                    werkBonusElementen, CheckBasisRszPositief.DEFAULT);
        }
    }

    private Money bepaalMaxOverdrachtWerkbonus(
            Collection<LoonElement> loonElementen, Money bestaandeOverdrachtWerkbonus, Opper opper,
            RekenTijd rekenTijd, RegulManager regulManager) {
        Money basis = Money.ZERO;
        for (LoonElement loonElement : loonElementen) {
            if (EXTRA_LOONCODES_OVERDRACHT.contains(loonElement.getAardKodeExtensie().getCode())) {
                basis = basis.add(loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_NIET_ONDERWORPEN_KEY));
            }
        }
        BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        BigDecimal percentage = bijdragePercentages.getInhoudingRsz(gegevens);
        return basis.multiply(percentage).round(2).add(bestaandeOverdrachtWerkbonus);
    }

    private Collection<LoonElement> bepaalWerkBonusElementen(
            Money bedragVermindering, RekenContext opdrachtContext, Opdracht opdracht,
            RekenTijd rekenTijd) {
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = opdrachtContext.getUnchecked(RekenChainKey.RKM_COREHR_CONFIG_MANAGER);
        Collection<LoonElement> werkBonusElementen = LoonElement.createSortedSet();
        for (LoonElement loonElement : manager.getOpdrachtsElementen(opdracht)) {
            SleutelGegevensSingleOpper gegevens = new SleutelGegevensSingleOpper(loonElement.getOpper());
            if (komtInAanMerking.checkOpdracht(opdracht, rekenTijd) &&
                    komtInAanMerking.checkSleutelGegevens(gegevens, rekenTijd, regulManager, rkmCoreHrConfiguratieManager) &&
                    inAanmerkingVerdeling(loonElement, gegevens, rekenTijd)) {
                werkBonusElementen.add(loonElement);
            }
        }
        if (werkBonusElementen.isEmpty() && bedragVermindering.signum() != 0) {
            werkBonusElementen = manager.getOpdrachtsElementen(opdracht);
        }
        return werkBonusElementen;
    }

    private boolean inAanmerkingVerdeling(LoonElement loonElement, SleutelGegevens gegevens, RekenTijd rekenTijd) {
        return rekenTijd.beginDatum.isBefore(START_WIJZING_WERKBONUS_VERDELING) || komtInAanMerking.checkLoonElement(gegevens, loonElement, rekenTijd) ||
                EXTRA_LOONCODES_VERDELING.contains(loonElement.getAardKodeExtensie().getCode());
    }

    private Money bepaalNegatieveBijdragen(Collection<LoonElement> werkBonusElementen) {
        Money negatieveBijdragen = Money.ZERO;
        for (LoonElement loonElement : werkBonusElementen) {
            Money bijdrage = loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
            bijdrage = bijdrage.add(loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY));
            if (bijdrage.signum() < 0) {
                negatieveBijdragen = negatieveBijdragen.add(bijdrage);
            }
        }
        return negatieveBijdragen;
    }

    private Money bepaalTotaalPositieveBasis(Collection<LoonElement> werkBonusElementen) {
        Money totaalBasis = Money.ZERO;
        for (LoonElement loonElement : werkBonusElementen) {
            Money basis = loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY);
            basis = basis.add(loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_TAO_KEY));
            if (basis.signum() > 0) {
                totaalBasis = totaalBasis.add(basis);
            }
        }
        return totaalBasis;
    }
}
